import{_ as o,o as r,c as a,a3 as t}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse(`{"title":"21. Ordinary Hours Of Work And Rostering","description":"","frontmatter":{"title":"21. Ordinary Hours Of Work And Rostering","eba":"Children's Services Award 2010","topics":["leave","personal-leave","annual-leave","public-holidays","hours","overtime","shift-work","rosters","wages","employment","disputes","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/hours-of-work/21-ordinary-hours-of-work-and-rostering.md","filePath":"ebas/childrens-services/hours-of-work/21-ordinary-hours-of-work-and-rostering.md"}`),n={name:"ebas/childrens-services/hours-of-work/21-ordinary-hours-of-work-and-rostering.md"};function i(s,e,l,d,p,h){return r(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="_21-ordinary-hours-of-work-and-rostering" tabindex="-1">21. Ordinary Hours Of Work And Rostering <a class="header-anchor" href="#_21-ordinary-hours-of-work-and-rostering" aria-label="Permalink to &quot;21. Ordinary Hours Of Work And Rostering&quot;">​</a></h1><ol><li><p>The ordinary hours of work of full-time employees will be an average of 38 hours per week over a one, two or four week cycle.</p></li><li><p>Ordinary hours will be worked in periods not exceeding eight hours, in unbroken periods save for meal breaks, between Monday and Friday. Subject to the provisions of <a href="/eba/ebas/childrens-services/application-operation/7-individual-flexibility-arrangements.html">clause 7</a>---Individual flexibility arrangements, by agreement between an employer and an employee, an employee may be rostered to work up to a maximum of 10 hours in any one day.</p></li><li><p>Ordinary hours may be worked between 6.00 am and 6.30 pm. Where broken shifts are worked the spread of hours can be no greater than 12 hours per day.</p></li><li><p>Rostered time off for full-time employees</p><p>a. The method of rostering the 38 hour week may be by any of the following:</p><pre><code>i.  by employees working less than eight ordinary hours per day;

ii. by employees working less than eight ordinary hours on one
    or more days each week;

iii. by rostering employees off on various days of the week
     during the work cycle; or

iv. by accumulating rostered days off with a maximum of five
    such days being taken consecutively at times mutually
    convenient to the employer and the employee.
</code></pre><p>b. In the absence of agreement at a workplace in respect to rostering of the 38 hour week the provisions of clause 9---Dispute resolution will apply.</p></li><li><p>Non-contact time</p></li></ol><p>[21.5(a) substituted by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR723626.htm" target="_blank" rel="noreferrer">PR723626</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR724049.htm" target="_blank" rel="noreferrer">PR724049</a> ppc 01Nov20]</p><p>a. An employee responsible for the preparation, implementation and/or evaluation of a developmental program for an individual child or group of children will be entitled to a minimum of two hours non-contact time per week. During non-contact time, an employee will not be required to supervise children or perform other duties as directed by the employer.</p><p>b. An employee appointed as the Educational Leader will be entitled to a minimum of two hours non-contact time per week. During non-contact time, an employee will not be required to supervise children or perform other duties as directed by the employer.</p><p>NOTE 1: Educational leader is defined in Regulation 118 of the <em>Education and Care Services National Regulations (2011)</em>.</p><p>NOTE 2: The entitlements at clauses 21.5(a) and 21.5(b) are cumulative. An Educational Leader who also has programming responsibilities for an individual child or group of children will be entitled to a minimum of four hours non-contact time per week.</p><p>[21.5(b) renumbered as 21.5(c) by <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR723626.htm" target="_blank" rel="noreferrer">PR723626</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR724049.htm" target="_blank" rel="noreferrer">PR724049</a> ppc 01Nov20]</p><p>c. Wherever possible non-contact time should be rostered in advance.</p><ol><li>Attendance at court</li></ol><p>Where it is necessary for an employee to attend court on the employer&#39;s, or the employer&#39;s clients, behalf in connection with any matter arising out of or in connection with their employment, the time taken will count as time worked.</p><ol><li><p>Rostering</p><p>a. An employer will post a legible roster at a place readily accessible to employees indicating the rostered hours of work.</p></li></ol><p>[21.7(b) substituted by <a href="http://www.fwc.gov.au/documents/awardsandorders/html/PR530861.htm" target="_blank" rel="noreferrer">PR530861</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR723626.htm" target="_blank" rel="noreferrer">PR723626</a>, <a href="https://www.fwc.gov.au/documents/awardsandorders/html/PR724049.htm" target="_blank" rel="noreferrer">PR724049</a> ppc 01Nov20]</p><p>b.</p><pre><code>i.  An employer may change an employee&#39;s rostered hours, but only by
    giving the employee seven days&#39; notice. In the absence of such
    notice overtime will be paid until seven days have elapsed from
    the date the notice was given. However, an employee and employer
    may agree to waive or shorten this notice period in a particular
    case. Such agreement may be made by electronic means of
    communication and must be recorded in the time and wages
    records.

ii. The employer is also not required to provide the full 7 days&#39;
    notice where the employer makes the change as a result of an
    emergency outside of the employer&#39;s control.

ii. It is not an emergency for the purposes of clause 21.7(b)(ii) if
    an employee is required to stay beyond their rostered hours
    because a parent fails to arrive on time to collect a child.

iii. For the purposes of clause 21.7(b)(ii), the overtime provisions
     in [clause 23](23-overtime-and-penalty-rates.md).2(c) apply.

iv. In clause 21.7(b)(ii), ***emergency*** means:
</code></pre><ul><li><p>a situation or event that poses an imminent or severe risk to the persons at an education and care service premises (for example, a fire at the education and care services premises); or</p></li><li><p>a situation that requires the education and care service premises to be locked-down (for example, an emergency government direction).</p><p>a. An employee may be transferred from one location to another within their rostered hours at the direction of the employer. An employee transferring from one location to another during a shift will be paid for the time taken to travel from one location to the other.</p><p>b. Where an employee is required to permanently transfer to another location (other than by mutual agreement) they must be given seven days&#39; notice of the change or paid overtime until seven days have transpired from the date notice was given.</p><ol><li>Make-up time</li></ol></li></ul><p>An employee may elect, with the consent of their employer, to work make-up time under which the employee takes time off during ordinary hours and works those hours at a later time during the ordinary spread of hours provided for in clause 21.3 at the ordinary rate of pay.</p><ol><li><p>Hours of work---out-of-school hours care, preschools and kindergartens</p><p>a. An employee in an out-of-school hours care service, preschool or kindergarten may be employed as a term-time employee to work:</p><pre><code>i.  only the school education weeks of the year as defined;

ii. an average of 38 ordinary hours per week of the school
    education year; or

iii. less than an average of 38 hours per week of the school
     education year.
</code></pre><p>b. All entitlements for term-time employees are no less than those for non term‑time employees, except that no ordinary wages are payable for the weeks the employee is not engaged to work.</p><p>c. Notwithstanding clause 21.9(b) non-engaged periods count as service for the purposes of accrual of paid annual and personal/carer&#39;s leave and wage increments.</p><p>d. Where a public holiday falls on a day on which a term-time employee is normally employed to work, the employee will be paid at the ordinary hourly rate of pay for the number of hours they would ordinarily have worked on that day.</p><p>e. Annual leave is exclusive of any public holiday which may occur during the period of leave provided the employee would have ordinarily been required to work on the day on which the public holiday falls.</p><p>f. Nothing in this clause prevents an employee in a preschool or kindergarten from being employed other than as a term-time only employee.</p></li></ol><p>[21.9(g) varied by <a href="http://www.fwc.gov.au/documents/awardsandorders/html/PR503637.htm" target="_blank" rel="noreferrer">PR503637</a> ppc 01Jan11]</p><p>g. Where a person employed as at the date of making this award is employed on a contract which provides for payment of salary during non-term times or is employed under an award-based transitional instrument or Division 2B State award which provides for such payments the provisions of this clause will not have the effect that their contract of employment is changed as a result of this award coming into operation.</p><p>h. The making of this award is not intended to prevent other arrangements for staff, who are not required to work during non-term weeks, to be agreed between the employer and majority of employees in a preschool, kindergarten or out-of-school hours care service.</p><p>Plain language terms: ordinary hours, rosters.</p>`,22)])])}const u=o(n,[["render",i]]);export{c as __pageData,u as default};
